// Phase 3 CRM Mock Data — Nextil 360
import type { TagCRM } from "./mockCRM";

export type ClienteStatus = "ativo" | "inativo" | "em_risco" | "reativacao" | "novo";
export type Nicho = "infantil" | "adulto" | "fitness" | "multimarcas" | "moda_praia" | "casual";
export type ConversaStatus = "ativa" | "aguardando_resposta" | "nao_lida" | "arquivada";

export interface Cliente360 {
  id: string;
  razaoSocial: string;
  nomeFantasia: string;
  documento: string;
  telefone: string;
  whatsapp: string;
  email: string;
  endereco: string;
  cidade: string;
  estado: string;
  representante: string;
  nicho: Nicho;
  interessePrincipal: string;
  marcasInteresse: string[];
  tags: TagCRM[];
  origem: string;
  status: ClienteStatus;
  dataCadastro: string;
  ultimoContato: string;
  proximaAcao: string;
  oportunidadesAbertas: number;
  orcamentosAtivos: number;
  pedidosRealizados: number;
  temperaturaComercial: "fria" | "morna" | "quente";
}

export interface Mensagem {
  id: string;
  conversaId: string;
  remetente: "cliente" | "vendedor";
  texto: string;
  horario: string;
  data: string;
  lida: boolean;
  tipo?: "texto" | "imagem" | "template" | "audio";
  // Status de entrega (somente mensagens enviadas pelo vendedor).
  // Conforme dados disponíveis na API do WhatsApp integrado.
  status?: "enviado" | "entregue" | "lido";
}

export interface Conversa {
  id: string;
  clienteId: string;
  clienteNome: string;
  clienteAvatar?: string;
  ultimaMensagem: string;
  ultimaHora: string;
  naoLidas: number;
  status: ConversaStatus;
  online?: boolean;
}

export type PedidoStatus = "confirmado" | "em_producao" | "faturado" | "em_transporte" | "entregue" | "cancelado" | "enviado";
export type PedidoOrigem = "orcamento" | "marketplace" | "manual";
export type PagamentoStatus = "pendente" | "pago" | "parcial" | "atrasado";

export interface PedidoItem {
  produtoId: string;
  nome: string;
  sku: string;
  cor: string;
  tamanho: string;
  qtd: number;
  precoUnit: number;
}

export interface PedidoPagamento {
  status: PagamentoStatus;
  metodo?: string;
  linkBoleto?: string;
  linkPagamento?: string;
  notaFiscal?: string;
}

export interface PedidoHistorico {
  status: PedidoStatus;
  data: string;
  autor: string;
}

export interface Pedido {
  id: string;
  clienteId: string;
  numero: string;
  data: string;
  valor: number;
  status: PedidoStatus;
  origem: string;
  observacoes: string;
  // novos campos (opcionais para retrocompat)
  origemTipo?: PedidoOrigem;
  orcamentoId?: string;
  marca?: string;
  pecas?: number;
  previsaoEntrega?: string;
  pagamento?: PedidoPagamento;
  itens?: PedidoItem[];
  historico?: PedidoHistorico[];
}

export interface Nota {
  id: string;
  clienteId: string;
  texto: string;
  data: string;
  autor: string;
  fixada: boolean;
}

export interface Compromisso {
  id: string;
  titulo: string;
  clienteId?: string;
  clienteNome?: string;
  oportunidadeId?: string;
  tipo: "ligacao" | "reuniao" | "visita" | "follow_up" | "retorno_orcamento" | "apresentacao";
  data: string;
  hora: string;
  duracao: string;
  responsavel: string;
  descricao: string;
  status: "agendado" | "concluido" | "cancelado";
}

export interface TarefaCRM360 {
  id: string;
  titulo: string;
  descricao: string;
  tipo: "ligacao" | "follow_up" | "visita" | "reuniao" | "retorno_proposta" | "cobranca_resposta" | "pos_venda";
  clienteId?: string;
  clienteNome?: string;
  oportunidadeId?: string;
  oportunidadeNome?: string;
  prioridade: "alta" | "media" | "baixa";
  vencimento: string;
  hora?: string;
  responsavel: string;
  // Status stored: só "pendente" | "concluida" | "cancelada".
  // "atrasada" é DERIVADA pelo helper statusDerivado(vencimento < hoje).
  status: "pendente" | "concluida" | "cancelada";
  lembrete?: string;
  observacao?: string;
  // Origem canônica da Ação (item 7 do método)
  origem?: "vendedor" | "sistema" | "atendimento" | "funil";
  // Loop do método: registro do "fiz" + encadeamento da próxima ação
  resultado?: string;
  proximaAcaoId?: string;
}

